#include <bits/stdc++.h>
#define ull unsigned long long
#define mk make_pair
#define PII pair<int,int>
#define NoAns puts("-1");
#define FOR(i,j,k) for(int i=(j);i<=(k);++i)
#define ROF(i,j,k) for(int i=(j);i>=(k);--i)
#define FOI(a,b) for(auto a : b)
#define Yes puts("Yes");
#define No puts("No");
#define llinf 0x3f3f3f3f3f3f3f3f
#define inf 0x3f3f3f3f
#define ll long long
#define snd second
#define fst first
#define il inline
#define pb push_back
#define CI const int
#define cl(x) memset(x,0,sizeof x)
#define cli(x) memset(x,0x3f,sizeof x)
#define lowbit(x) (x&(-x))
#define wh while
#define gc() getchar()
#define pc(x) putchar(x)
#define NP namespace
using NP std;
il ll read()
{
    ll x=0,f=1;char ch=gc();
    wh(ch<'0'||ch>'9'){if(ch=='-')f=-1;ch=getchar();}
    wh(ch>='0'&&ch<='9'){x=x*10+ch-'0';ch=gc();}
    return x*f;
}
void write(ll x)
{
    if(x<0)pc('-'),x=-x;
    if(x>9)write(x/10);
    pc(x%10+'0');
}
void writeln(ll x)
{
    write(x);
    puts("");
    return;
}
CI MAXN=1e5+5;
vector<int> G[MAXN];
int n,vis[MAXN],a[MAXN],ans=0;
int dfs(int x)
{  
    if(vis[x])return vis[x];
    int cnt=0;
    FOI(v,G[x])
    {
        if(a[x]>a[v])cnt+=dfs(v);
    }
    return vis[x]=cnt+1;
}
int main(void)
{
    // freopen("in.txt","r",stdin);
    // freopen("out.txt","w",stdout);
    n=read();
    FOR(i,1,n)
    {
        a[i]=read();
    }
    FOR(i,1,n-1)
    {
        int u=read(),v=read();
        G[u].pb(v);
        G[v].pb(u);
    }
    FOR(i,1,n)
    {
        ans=max(ans,dfs(i));
    }
    writeln(ans);
    return false;
}
